{
  "app_structure": {
    "tech_stack": "Vite + React + TypeScript",
    "file_scope": [
      "package.json",
      "index.html",
      "src/main.tsx",
      "src/App.tsx",
      "src/App.css",
      "src/vite-env.d.ts"
    ],
    "architecture": {
      "entry": "src/main.tsx mounts <App /> into #root with React.StrictMode",
      "single_component_pattern": "All page views and reusable UI blocks are defined in src/App.tsx to keep implementation contained",
      "navigation": "Local state enum/string union for active page (overview | routing-lab | eval-report), switched via top nav buttons",
      "data_model": "In-file typed constants for Thompson routing metrics, model candidates, alpha/beta stats, and eval rows"
    }
  },
  "design_system": {
    "style_source": "src/App.css only (no Tailwind, no UI libraries)",
    "visual_language": {
      "theme": "Dark polished command-center aesthetic with gradient hero and elevated cards",
      "layout": "Responsive shell with sticky top nav, hero banner, metric grid, and content cards",
      "tokens": {
        "colors": {
          "bg": "#0b1020",
          "surface": "#121a2b",
          "surfaceAlt": "#18233a",
          "text": "#e8edf7",
          "muted": "#9fb0cd",
          "primary": "#6ea8ff",
          "accent": "#63e6be",
          "warning": "#ffd166"
        },
        "radius": "12px / 16px card and panel radii",
        "shadow": "Soft layered shadows for depth",
        "spacing": "8px baseline scale",
        "typography": "System stack with strong headings and compact metric labels"
      }
    },
    "components": [
      "TopNav with page tabs and active indicator",
      "Hero panel with title 'Agent Sam Command Center' and summary chips",
      "MetricCard component style (pass rate, latency, cost, alpha/beta, candidate count)",
      "DataCard/Table styles for routing lab and eval report",
      "Status pills/badges for models including gpt-5.3-codex, gpt-5.4-mini, gpt-5.4-nano"
    ]
  },
  "page_specs": {
    "overview": {
      "purpose": "Executive snapshot of Thompson routing health",
      "sections": [
        "Hero with app title, short mission statement, and current experiment tag",
        "Primary metrics grid: pass rate, p95 latency, avg cost, alpha/beta split, active model candidates",
        "Model candidate cards explicitly listing gpt-5.3-codex, gpt-5.4-mini, gpt-5.4-nano with mock scores",
        "Recent activity timeline/list"
      ]
    },
    "routing_lab": {
      "purpose": "Interactive mock controls for routing strategy",
      "sections": [
        "Control card with local state sliders/inputs for alpha, beta, exploration rate",
        "Preview card showing computed traffic allocation percentages per model candidate",
        "Scenario cards (low latency, low cost, balanced quality) with selectable state",
        "Metric delta row comparing baseline vs tuned values"
      ]
    },
    "eval_report": {
      "purpose": "Readable benchmark outputs",
      "sections": [
        "Summary strip with run ID/date/status",
        "Table-like grid of mock eval categories (reasoning, tool-use, safety, format adherence) and scores",
        "Per-model comparison rows including gpt-5.3-codex, gpt-5.4-mini, gpt-5.4-nano",
        "Key findings and next-step bullets"
      ]
    }
  },
  "validation_notes": {
    "build": [
      "Use standard Vite scripts in package.json: dev, build, preview",
      "Include React, ReactDOM, TypeScript, Vite, and @types packages only",
      "Ensure imports are relative and compile under strict TS defaults"
    ],
    "requirements_checklist": [
      "3 local-state navigated pages implemented in App.tsx",
      "No external UI library usage",
      "No Tailwind dependency",
      "All styling in src/App.css",
      "Polished UI elements: hero, cards, metrics, gradients, responsive nav/layout",
      "Thompson routing mock metrics included",
      "Model names included verbatim: gpt-5.3-codex, gpt-5.4-mini, gpt-5.4-nano",
      "Project buildable with npm install && npm run build"
    ],
    "simplicity_constraints": "Keep logic declarative and lightweight; avoid extra files, routers, or state libraries."
  }
}
